mapper.select:
select
    id,
    tenant_id,
    pipeline_definition_id,
    job_code,
    pipeline_type,
    file_id,
    related_job_instance_id,
    current_stage,
    last_success_stage,
    run_status,
    trace_id,
    started_at,
    finished_at,
    created_at,
    updated_at
from batch.pipeline_instance
where tenant_id = #{q.tenantId}

    and file_id = #{q.fileId}


    and id = #{q.pipelineInstanceId}


    and pipeline_type = #{q.pipelineType}


    and run_status = #{q.runStatus}


    and trace_id = #{q.traceId}


    and created_at >= #{q.fromTime}


    and created_at <= #{q.toTime}

order by id desc

    limit #{q.pageRequest.pageSize} offset (#{q.pageRequest.pageNo} - 1) * #{q.pageRequest.pageSize}

select count(1)
from batch.pipeline_instance
where tenant_id = #{q.tenantId}

    and file_id = #{q.fileId}


    and id = #{q.pipelineInstanceId}


    and pipeline_type = #{q.pipelineType}


    and run_status = #{q.runStatus}


    and trace_id = #{q.traceId}


    and created_at >= #{q.fromTime}


    and created_at <= #{q.toTime}

select count(*)
  from batch.pipeline_instance
 where tenant_id = #{tenantId}
   and run_status in
#{s}
